option.value:
/* ── Reset & Base ─────────────────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg:        #0a0a0a;
  --bg2:       #111111;
  --bg3:       #1a1a1a;
  --border:    #2a2a2a;
  --red:       #cc0000;
  --red-dim:   #8b0000;
  --red-glow:  rgba(204, 0, 0, 0.35);
  --text:      #e0e0e0;
  --text-dim:  #888888;
  --text-code: #f0a0a0;
  --user-bg:   #1c1010;
  --ai-bg:     #0f1a0f;
  --radius:    8px;
  --font:      'Segoe UI', system-ui, -apple-system, sans-serif;
  --font-mono: 'Consolas', 'Courier New', monospace;
}

html, body {
  height: 100%;
  background: var(--bg);
  color: var(--text);
  font-family: var(--font);
  font-size: 14px;
  line-height: 1.6;
  overflow: hidden;
}

/* ── Header ──────────────────────────────────────────────────────────── */
.app-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 20px;
  height: 52px;
  background: var(--bg2);
  border-bottom: 1px solid var(--border);
  box-shadow: 0 2px 12px rgba(204,0,0,0.15);
  flex-shrink: 0;
}

.header-left {
  display: flex;
  align-items: center;
  gap: 12px;
}

.app-title {
  font-size: 20px;
  font-weight: 700;
  color: var(--red);
  letter-spacing: 1px;
  text-shadow: 0 0 12px var(--red-glow);
}

.header-right {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
  color: var(--text-dim);
}

.status-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: #555;
  transition: background 0.3s;
}
.status-dot.ok    { background: #22aa22; box-shadow: 0 0 6px #22aa22; }
.status-dot.error { background: var(--red); box-shadow: 0 0 6px var(--red); }
.status-dot.busy  { background: #ddaa00; box-shadow: 0 0 6px #ddaa00; animation: pulse 1s infinite; }

@keyframes pulse { 0%,100% { opacity:1; } 50% { opacity:0.4; } }

/* ── Layout ──────────────────────────────────────────────────────────── */
.app-main {
  display: flex;
  height: calc(100vh - 52px);
  overflow: hidden;
}

/* ── HAL Panel ───────────────────────────────────────────────────────── */
.hal-panel {
  width: 260px;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 24px 16px 16px;
  background: var(--bg2);
  border-right: 1px solid var(--border);
  gap: 12px;
  overflow-y: auto;
}

#halEye { display: block; }

.hal-label {
  font-size: 18px;
  font-weight: 700;
  color: var(--red);
  letter-spacing: 2px;
  text-shadow: 0 0 10px var(--red-glow);
}

.hal-status {
  font-size: 12px;
  color: var(--text-dim);
  text-align: center;
  font-style: italic;
  min-height: 32px;
}

.info-box {
  width: 100%;
  background: var(--bg3);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 10px 12px;
}
.info-row {
  display: flex;
  justify-content: space-between;
  padding: 3px 0;
  font-size: 12px;
  border-bottom: 1px solid #1e1e1e;
}
.info-row:last-child { border-bottom: none; }
.info-key { color: var(--text-dim); }
.info-val { color: var(--text); font-weight: 500; max-width: 140px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.info-val.ok    { color: #44cc44; }
.info-val.error { color: var(--red); }

/* ── Chat Panel ──────────────────────────────────────────────────────── */
.chat-panel {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 16px;
  scroll-behavior: smooth;
}

/* Custom scrollbar */
.chat-messages::-webkit-scrollbar { width: 6px; }
.chat-messages::-webkit-scrollbar-track { background: var(--bg); }
.chat-messages::-webkit-scrollbar-thumb { background: #333; border-radius: 3px; }
.chat-messages::-webkit-scrollbar-thumb:hover { background: var(--red-dim); }

/* ── Message bubbles ─────────────────────────────────────────────────── */
.message {
  display: flex;
  flex-direction: column;
  max-width: 85%;
  animation: fadeIn 0.3s ease;
}
@keyframes fadeIn { from { opacity:0; transform: translateY(6px); } to { opacity:1; transform: translateY(0); } }

.message.user   { align-self: flex-end; align-items: flex-end; }
.message.aigeny { align-self: flex-start; align-items: flex-start; }

.message-header {
  font-size: 11px;
  color: var(--text-dim);
  margin-bottom: 4px;
  display: flex;
  align-items: center;
  gap: 6px;
}
.message-header .dot {
  width: 6px; height: 6px; border-radius: 50%;
}
.message.user   .dot { background: #5588ff; }
.message.aigeny .dot { background: var(--red); box-shadow: 0 0 4px var(--red); }

.message-bubble {
  padding: 12px 16px;
  border-radius: var(--radius);
  line-height: 1.7;
  word-break: break-word;
}
.message.user   .message-bubble {
  background: var(--user-bg);
  border: 1px solid #2a1a1a;
  color: #ddd;
}
.message.aigeny .message-bubble {
  background: var(--ai-bg);
  border: 1px solid #1a2a1a;
  color: var(--text);
}

/* Markdown-style content in messages */
.message-bubble strong { color: #ffcccc; }
.message-bubble em     { color: var(--text-dim); }
.message-bubble code   { background: #1e1e1e; color: var(--text-code); padding: 1px 5px; border-radius: 3px; font-family: var(--font-mono); font-size: 12px; }
.message-bubble pre    { background: #0d0d0d; border: 1px solid #2a2a2a; border-radius: 4px; padding: 10px 12px; overflow-x: auto; margin: 8px 0; }
.message-bubble pre code { background: none; padding: 0; color: #cc8888; }
.message-bubble table  { border-collapse: collapse; width: 100%; margin: 8px 0; font-size: 12px; }
.message-bubble th     { background: var(--red-dim); color: #fff; padding: 6px 10px; text-align: left; }
.message-bubble td     { padding: 5px 10px; border-bottom: 1px solid #1e1e1e; }
.message-bubble tr:nth-child(even) td { background: #0e0e0e; }
.message-bubble h1,.message-bubble h2,.message-bubble h3 { color: var(--red); margin: 8px 0 4px; }
.message-bubble ul,.message-bubble ol { margin-left: 20px; margin-top: 4px; }
.message-bubble li { margin-bottom: 2px; }

/* Typing indicator */
.typing-indicator {
  display: flex;
  gap: 5px;
  align-items: center;
  padding: 10px 14px;
}
.typing-indicator span {
  width: 7px; height: 7px;
  background: var(--red);
  border-radius: 50%;
  animation: bounce 1.2s infinite;
}
.typing-indicator span:nth-child(2) { animation-delay: 0.2s; }
.typing-indicator span:nth-child(3) { animation-delay: 0.4s; }
@keyframes bounce { 0%,80%,100% { transform: translateY(0); } 40% { transform: translateY(-6px); } }

/* ── Input area ──────────────────────────────────────────────────────── */
.input-area {
  display: flex;
  gap: 8px;
  padding: 12px 20px;
  border-top: 1px solid var(--border);
  background: var(--bg2);
}

#userInput {
  flex: 1;
  background: var(--bg3);
  color: var(--text);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 10px 14px;
  font-family: var(--font);
  font-size: 14px;
  resize: none;
  outline: none;
  transition: border-color 0.2s;
  line-height: 1.5;
}
#userInput:focus { border-color: var(--red-dim); }
#userInput::placeholder { color: #444; }

.btn-send {
  background: var(--red);
  color: #fff;
  border: none;
  border-radius: var(--radius);
  padding: 0 22px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.2s, box-shadow 0.2s;
  white-space: nowrap;
}
.btn-send:hover:not(:disabled) { background: #ee1111; box-shadow: 0 0 14px var(--red-glow); }
.btn-send:disabled { background: #3a1a1a; color: #666; cursor: not-allowed; }

/* ── Action bar ──────────────────────────────────────────────────────── */
.action-bar {
  display: flex;
  gap: 8px;
  padding: 8px 20px 12px;
  background: var(--bg2);
}

.btn-export {
  background: var(--bg3);
  color: var(--text-dim);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 6px 16px;
  font-size: 12px;
  cursor: pointer;
  transition: all 0.2s;
}
.btn-export:hover:not(:disabled) { border-color: var(--red-dim); color: var(--red); }
.btn-export:disabled { opacity: 0.3; cursor: not-allowed; }

.btn-secondary {
  background: transparent;
  color: var(--text-dim);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 6px 14px;
  font-size: 12px;
  cursor: pointer;
  transition: all 0.2s;
}
.btn-secondary:hover { border-color: #555; color: var(--text); }

/* ── Responsive ──────────────────────────────────────────────────────── */
@media (max-width: 700px) {
  .hal-panel { display: none; }
  .message { max-width: 95%; }
}

/* ── Jira Write Mode Toggle ───────────────────────────────────────────── */
.write-mode-toggle {
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--bg3);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 8px 12px;
  gap: 8px;
}
.write-mode-label {
  font-size: 12px;
  color: var(--text-dim);
  white-space: nowrap;
  transition: color 0.2s;
}
.toggle-switch {
  position: relative;
  display: inline-block;
  width: 38px;
  height: 21px;
  flex-shrink: 0;
}
.toggle-switch input { opacity: 0; width: 0; height: 0; }
.toggle-slider {
  position: absolute;
  inset: 0;
  background: #2a2a2a;
  border: 1px solid #444;
  border-radius: 21px;
  cursor: pointer;
  transition: background 0.2s, border-color 0.2s;
}
.toggle-slider::before {
  content: '';
  position: absolute;
  height: 15px;
  width: 15px;
  left: 2px;
  top: 2px;
  background: #666;
  border-radius: 50%;
  transition: transform 0.2s, background 0.2s;
}
.toggle-switch input:checked + .toggle-slider {
  background: #2a0a0a;
  border-color: var(--red-dim);
}
.toggle-switch input:checked + .toggle-slider::before {
  transform: translateX(17px);
  background: var(--red);
  box-shadow: 0 0 6px var(--red-glow);
}

/* ── Token button in info-row ─────────────────────────────────────────── */
.btn-token {
  display: none;
  background: transparent;
  color: var(--red);
  border: 1px solid var(--red-dim);
  border-radius: 4px;
  padding: 2px 7px;
  font-size: 10px;
  cursor: pointer;
  transition: all 0.2s;
  white-space: nowrap;
  flex-shrink: 0;
  margin-left: 4px;
}
.btn-token:hover { background: var(--red-dim); color: #fff; }
.btn-token.visible { display: inline-block; }
.info-row { align-items: center; }

/* ── Modal ────────────────────────────────────────────────────────────── */
.modal-overlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,0.75);
  display: flex; align-items: center; justify-content: center;
  z-index: 1000;
}
.modal-box {
  background: var(--bg2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 28px 32px;
  max-width: 440px; width: 90%;
  box-shadow: 0 8px 40px rgba(204,0,0,0.25);
}
.modal-box h2 { color: var(--red); margin-bottom: 14px; font-size: 16px; }
.modal-desc {
  color: var(--text-dim);
  font-size: 12px;
  line-height: 1.7;
  margin-bottom: 16px;
}
.modal-desc strong { color: var(--text); }
.modal-desc em     { color: var(--text); font-style: normal; }
.modal-input {
  width: 100%;
  background: var(--bg3);
  color: var(--text);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 10px 12px;
  font-size: 13px;
  font-family: var(--font-mono);
  outline: none;
  margin-bottom: 8px;
  transition: border-color 0.2s;
}
.modal-input:focus { border-color: var(--red-dim); }
.modal-hint { font-size: 11px; min-height: 18px; margin-bottom: 14px; }
.modal-hint.ok    { color: #44cc44; }
.modal-hint.error { color: var(--red); }
.modal-actions { display: flex; gap: 8px; flex-wrap: wrap; }

/* ── Jira Confirmation Block ───────────────────────────────────────────── */
.jira-confirm-msg .message-bubble {
  border: 1px solid #cc6600;
  background: #1a1000;
}
.jira-confirm-buttons {
  display: flex;
  gap: 10px;
  margin-top: 12px;
  flex-wrap: wrap;
}
.btn-confirm {
  background: #1a4a1a;
  color: #88ee88;
  border: 1px solid #338833;
  padding: 7px 18px;
  border-radius: var(--radius);
  cursor: pointer;
  font-size: 13px;
  font-weight: 600;
  transition: background 0.2s, border-color 0.2s;
}
.btn-confirm:hover:not(:disabled) { background: #225522; border-color: #44aa44; }
.btn-confirm:disabled { opacity: 0.45; cursor: not-allowed; }

.btn-cancel {
  background: #3a1010;
  color: #ee8888;
  border: 1px solid #883333;
  padding: 7px 18px;
  border-radius: var(--radius);
  cursor: pointer;
  font-size: 13px;
  font-weight: 600;
  transition: background 0.2s, border-color 0.2s;
}
.btn-cancel:hover:not(:disabled) { background: #4a1515; border-color: #aa4444; }
.btn-cancel:disabled { opacity: 0.45; cursor: not-allowed; }

