  resize: none;
  outline: none;
  transition: border-color 0.2s;
  line-height: 1.5;
}
#userInput:focus { border-color: var(--red-dim); }
#userInput::placeholder { color: #444; }

.btn-send {
  background: var(--red);
  color: #fff;
  border: none;
  border-radius: var(--radius);
  padding: 0 22px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.2s, box-shadow 0.2s;
  white-space: nowrap;
}
.btn-send:hover:not(:disabled) { background: #ee1111; box-shadow: 0 0 14px var(--red-glow); }
.btn-send:disabled { background: #3a1a1a; color: #666; cursor: not-allowed; }

/* ── Action bar ──────────────────────────────────────────────────────── */
.action-bar {
  display: flex;
  gap: 8px;
  padding: 8px 20px 12px;
  background: var(--bg2);
}

.btn-export {
  background: var(--bg3);
  color: var(--text-dim);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 6px 16px;
  font-size: 12px;
  cursor: pointer;
  transition: all 0.2s;
}
.btn-export:hover:not(:disabled) { border-color: var(--red-dim); color: var(--red); }
.btn-export:disabled { opacity: 0.3; cursor: not-allowed; }

.btn-secondary {
  background: transparent;
  color: var(--text-dim);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 6px 14px;
  font-size: 12px;
  cursor: pointer;
  transition: all 0.2s;
}
.btn-secondary:hover { border-color: #555; color: var(--text); }

/* ── Responsive ──────────────────────────────────────────────────────── */
@media (max-width: 700px) {
  .hal-panel { display: none; }
  .message { max-width: 95%; }
}

/* ── Jira Write Mode Toggle ───────────────────────────────────────────── */
.write-mode-toggle {
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: var(--bg3);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 8px 12px;
  gap: 8px;
}
.write-mode-label {
  font-size: 12px;
  color: var(--text-dim);
  white-space: nowrap;
  transition: color 0.2s;
}
.toggle-switch {
  position: relative;
  display: inline-block;
  width: 38px;
  height: 21px;
  flex-shrink: 0;
}
.toggle-switch input { opacity: 0; width: 0; height: 0; }
.toggle-slider {
  position: absolute;
  inset: 0;
  background: #2a2a2a;
  border: 1px solid #444;
  border-radius: 21px;
  cursor: pointer;
  transition: background 0.2s, border-color 0.2s;
}
.toggle-slider::before {
  content: '';
  position: absolute;
  height: 15px;
  width: 15px;
  left: 2px;
  top: 2px;
  background: #666;
  border-radius: 50%;
  transition: transform 0.2s, background 0.2s;
}
.toggle-switch input:checked + .toggle-slider {
  background: #2a0a0a;
  border-color: var(--red-dim);
}
.toggle-switch input:checked + .toggle-slider::before {
  transform: translateX(17px);
  background: var(--red);
  box-shadow: 0 0 6px var(--red-glow);
}

/* ── Token button in info-row ─────────────────────────────────────────── */
.btn-token {
  display: none;
  background: transparent;
  color: var(--red);
  border: 1px solid var(--red-dim);
  border-radius: 4px;
  padding: 2px 7px;
  font-size: 10px;
  cursor: pointer;
  transition: all 0.2s;
  white-space: nowrap;
  flex-shrink: 0;
  margin-left: 4px;
}
.btn-token:hover { background: var(--red-dim); color: #fff; }
.btn-token.visible { display: inline-block; }
.info-row { align-items: center; }

/* ── Modal ────────────────────────────────────────────────────────────── */
.modal-overlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,0.75);
  display: flex; align-items: center; justify-content: center;
  z-index: 1000;
}
.modal-box {
  background: var(--bg2);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 28px 32px;
  max-width: 440px; width: 90%;
  box-shadow: 0 8px 40px rgba(204,0,0,0.25);
}
.modal-box h2 { color: var(--red); margin-bottom: 14px; font-size: 16px; }
.modal-desc {
  color: var(--text-dim);
  font-size: 12px;
  line-height: 1.7;
  margin-bottom: 16px;
}
.modal-desc strong { color: var(--text); }
.modal-desc em     { color: var(--text); font-style: normal; }
.modal-input {
  width: 100%;
  background: var(--bg3);
  color: var(--text);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 10px 12px;
  font-size: 13px;
  font-family: var(--font-mono);
  outline: none;
  margin-bottom: 8px;
  transition: border-color 0.2s;
}
.modal-input:focus { border-color: var(--red-dim); }
.modal-hint { font-size: 11px; min-height: 18px; margin-bottom: 14px; }
.modal-hint.ok    { color: #44cc44; }
.modal-hint.error { color: var(--red); }
.modal-actions { display: flex; gap: 8px; flex-wrap: wrap; }

/* ── Jira Confirmation Block ───────────────────────────────────────────── */
.jira-confirm-msg .message-bubble {
  border: 1px solid #cc6600;
  background: #1a1000;
}
.jira-confirm-buttons {
  display: flex;
  gap: 10px;
  margin-top: 12px;
  flex-wrap: wrap;
}
.btn-confirm {
  background: #1a4a1a;
  color: #88ee88;
  border: 1px solid #338833;
  padding: 7px 18px;
  border-radius: var(--radius);
  cursor: pointer;
  font-size: 13px;
  font-weight: 600;
  transition: background 0.2s, border-color 0.2s;
}
.btn-confirm:hover:not(:disabled) { background: #225522; border-color: #44aa44; }
.btn-confirm:disabled { opacity: 0.45; cursor: not-allowed; }

.btn-cancel {
  background: #3a1010;
  color: #ee8888;
  border: 1px solid #883333;
  padding: 7px 18px;
  border-radius: var(--radius);
  cursor: pointer;
  font-size: 13px;
  font-weight: 600;
  transition: background 0.2s, border-color 0.2s;
}
.btn-cancel:hover:not(:disabled) { background: #4a1515; border-color: #aa4444; }
.btn-cancel:disabled { opacity: 0.45; cursor: not-allowed; }
